var subarraySum = function(nums, k) {
    const seen = new Map();
    seen.set(0, 1);
    let s = 0, count = 0;
    for (const x of nums) {
        s += x;
        count += seen.get(s - k) || 0;
        seen.set(s, (seen.get(s) || 0) + 1);
    }
    return count;
};
